const express = require('express');
const winston = require('winston');
const morgan = require('morgan');

// Set up logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf((info) => `${info.timestamp} ${info.level}: ${info.message}`),
  ),
  transports: [
    new winston.transports.File({ filename: 'logs/audit.log' }),
    new winston.transports.Console(),
  ],
});

// Set up Express app
const app = express();

// Use Morgan for request logging with custom format
app.use(morgan('combined', {
  skip: (req, res) => res.statusCode < 400,
  stream: logger.info,
}));

// Validate and sanitize user input
function validateUserInput(input) {
  const sanitizedInput = {};
  Object.keys(input).forEach((key) => {
    if (['username', 'ip_address'].includes(key)) {
      sanitizedInput[key] = input[key];
    } else if (['custom_header_1', 'custom_header_2'].includes(key)) {
      sanitizedInput[key] = input[key].trim();
    }
  });
  return sanitizedInput;
}

// Securely log user-provided data
app.post('/log', (req, res) => {
  const userInput = validateUserInput(req.body);
  logger.info({
    message: 'User provided data',
    username: userInput.username,
    ip_address: userInput.ip_address,
    custom_header_1: userInput.custom_header_1,
    custom_header_2: userInput.custom_header_2,
  });
  res.status(200).send('Data logged successfully');
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});